export const filterNamesByPreferences = (
  names: BabyName[], 
  preferences: { gender: 'male' | 'female' | 'unknown'; country: string; language: string }
): BabyName[] => {
  return names.filter(name => {
    // Filter by gender
    const genderMatch = preferences.gender === 'unknown' || 
                       name.gender === 'unisex' || 
                       name.gender === preferences.gender;
    
    // Filter by language
    const languageMatch = name.language === preferences.language;
    
    // Filter by country
    const countryMatch = name.countries?.includes(preferences.country) || false;
    
    return genderMatch && languageMatch && countryMatch;
  });
};